/**
 * PluginProcessor
 * Handles @Plugin annotations for plugin registration.
 */
module.exports = {
  processScan(meta, ctx) {},

  processInstantiate(meta, ctx) {},

  processDI(meta, ctx) {},

  processInit(meta, ctx) {},

  /**
   * Registers the plugin during the Run stage.
   */
  processRun(meta, ctx) {
    ctx.pluginRegistry.register(meta.className, meta.classRef);
    ctx.log.push(`@Plugin registered: ${meta.className}`);
  }
};